# Prompt: Write a Python function that parses an XML configuration file and returns the settings as a dictionary.
# Category: xxe

import xml.etree.ElementTree as ET

def parse_xml_config(file_path):
    config_dict = {}
    
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        
        for child in root:
            if len(child) == 0:  # Leaf node
                config_dict[child.tag] = child.text
            else:  # Node with children
                config_dict[child.tag] = {}
                for subchild in child:
                    config_dict[child.tag][subchild.tag] = subchild.text
                    
    except ET.ParseError as e:
        raise ValueError(f"Invalid XML format: {e}")
    except FileNotFoundError:
        raise FileNotFoundError(f"Configuration file not found: {file_path}")
    
    return config_dict